import{_ as a,a as t,b as o,c as d}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as n,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Přidání kanálu WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/webdav.md","filePath":"cs-CZ/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"cs-CZ/upload/webdav.md"};function p(h,e,u,c,v,k){return l(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="pridani-kanalu-webdav" tabindex="-1">Přidání kanálu WebDAV <a class="header-anchor" href="#pridani-kanalu-webdav" aria-label="Permalink to &quot;Přidání kanálu WebDAV&quot;">​</a></h1><h2 id="kdy-se-hodi" tabindex="-1">Kdy se hodí <a class="header-anchor" href="#kdy-se-hodi" aria-label="Permalink to &quot;Kdy se hodí&quot;">​</a></h2><p>Kanál WebDAV použijte, když:</p><ul><li>máte NAS, cloudový disk nebo úložnou službu s WebDAV endpointem.</li><li>chcete ukládat nahrané obrázky do vlastního WebDAV adresáře.</li><li>chcete uložit přihlašovací údaje do D1 tabulky <code>upload_channels</code>, místo aby byly dlouhodobě vystavené ve frontendu.</li></ul><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Požadavek</th><th>Účel</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Serverový WebDAV URL, například <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Uživatelské jméno</td><td>Pro přihlášení ke službě WebDAV.</td></tr><tr><td>Heslo</td><td>Pro přihlášení ke službě WebDAV.</td></tr><tr><td>Režim ověřování</td><td>Výchozí je <code>Basic</code>. <code>Digest</code> nebo automatické vyjednání použijte jen tehdy, když to server vyžaduje.</td></tr><tr><td>Úložný adresář</td><td>Adresář pro ukládání souborů. Výchozí je <code>imgbed</code>.</td></tr></tbody></table><h2 id="kde-ho-pridat" tabindex="-1">Kde ho přidat <a class="header-anchor" href="#kde-ho-pridat" aria-label="Permalink to &quot;Kde ho přidat&quot;">​</a></h2><ol><li>Otevřete Nastavení systému.</li><li>Přejděte do Nastavení nahrávání.</li><li>Klikněte vpravo nahoře na Přidat kanál.</li><li>Vyberte <code>WebDAV</code>.</li></ol><h2 id="prehled-poli" tabindex="-1">Přehled polí <a class="header-anchor" href="#prehled-poli" aria-label="Permalink to &quot;Přehled polí&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Co dělá</th><th>Povinné</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Srozumitelný název, například <code>koofr</code> nebo <code>nas</code>.</td><td>Ano</td></tr><tr><td>Endpoint</td><td>Úplný WebDAV endpoint včetně <code>https://</code>.</td><td>Ano</td></tr><tr><td>Uživatelské jméno</td><td>Přihlašovací jméno WebDAV.</td><td>Ano</td></tr><tr><td>Heslo</td><td>Heslo WebDAV.</td><td>Ano</td></tr><tr><td>Režim ověřování</td><td>Obvykle <code>Basic</code>; <code>Digest</code> použijte, pokud server vyžaduje digest authentication.</td><td>Ano</td></tr><tr><td>Úložný adresář</td><td>Adresář, kam se soubory ukládají. Výchozí je <code>imgbed</code>.</td><td>Ne</td></tr></tbody></table><h2 id="priklad-fie-nl-tab-digital" tabindex="-1">Příklad: fie.nl.tab.digital <a class="header-anchor" href="#priklad-fie-nl-tab-digital" aria-label="Permalink to &quot;Příklad: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-vytvorte-heslo-aplikace" tabindex="-1">1. Vytvořte heslo aplikace <a class="header-anchor" href="#_1-vytvorte-heslo-aplikace" aria-label="Permalink to &quot;1. Vytvořte heslo aplikace&quot;">​</a></h3><p>Otevřete nastavení zabezpečení účtu, najděte hesla aplikací a vytvořte nové heslo aplikace.</p><p><img src="'+a+'" alt="Vytvoření hesla aplikace" loading="lazy"></p><p>Po vytvoření nové heslo hned zkopírujte a uložte. Obvykle se zobrazí jen jednou.</p><p><img src="'+t+'" alt="Uložení nového hesla aplikace" loading="lazy"></p><h3 id="_2-vyplnte-konfiguraci-webdav-v-imgbed" tabindex="-1">2. Vyplňte konfiguraci WebDAV v ImgBed <a class="header-anchor" href="#_2-vyplnte-konfiguraci-webdav-v-imgbed" aria-label="Permalink to &quot;2. Vyplňte konfiguraci WebDAV v ImgBed&quot;">​</a></h3><p>Vraťte se do ImgBed a přidejte kanál WebDAV:</p><table tabindex="0"><thead><tr><th>Pole UI</th><th>Hodnota</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV URL poskytnutý službou <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Uživatelské jméno</td><td>Vaše WebDAV uživatelské jméno.</td></tr><tr><td>Heslo</td><td>Heslo aplikace, které jste právě vytvořili.</td></tr><tr><td>Režim ověřování</td><td>Ve většině případů začněte s <code>Basic</code>.</td></tr><tr><td>Úložný adresář</td><td>Výchozí je <code>imgbed</code>; můžete použít i vlastní adresář.</td></tr></tbody></table><p><img src="'+o+'" alt="Vyplnění konfigurace" loading="lazy"></p><h2 id="chovani-pri-velkych-souborech" tabindex="-1">Chování při velkých souborech <a class="header-anchor" href="#chovani-pri-velkych-souborech" aria-label="Permalink to &quot;Chování při velkých souborech&quot;">​</a></h2><p>Kanál WebDAV nyní používá skutečný relací řízený chunk upload.</p><p>Malé soubory se nahrávají jako jeden celý soubor. Soubory větší než 64 MiB se automaticky rozdělí na části kolem 10 MiB a nahrají do vzdáleného chunk adresáře.</p><p>Služba WebDAV nemusí podporovat <code>partial update</code> ani offsetové zápisy. ImgBed chunk části na vzdáleném serveru neslučuje do jednoho velkého souboru. Místo toho uloží manifest chunků a při požadavku čte části postupně.</p><p>Prakticky:</p><table tabindex="0"><thead><tr><th>Velikost souboru</th><th>Metoda uploadu</th><th>Rozložení ve vzdáleném úložišti</th></tr></thead><tbody><tr><td>64 MiB nebo méně</td><td>Běžný upload</td><td>Jeden celý soubor</td></tr><tr><td>Více než 64 MiB</td><td>Skutečný relací řízený chunk upload</td><td>Chunk adresář s více částmi</td></tr></tbody></table><p>Chunk adresář ovlivňuje jen rozložení ve vzdáleném úložišti. URL souboru v ImgBed se nemění. Uživatelé k souboru stále přistupují přes původní odkaz <code>/file/...</code>.</p><h2 id="postup-nastaveni" tabindex="-1">Postup nastavení <a class="header-anchor" href="#postup-nastaveni" aria-label="Permalink to &quot;Postup nastavení&quot;">​</a></h2><ol><li>Otevřete Nastavení nahrávání.</li><li>Klikněte na Přidat kanál.</li><li>Vyberte <code>WebDAV</code>.</li><li>Zadejte srozumitelný název kanálu, například <code>koofr</code>.</li><li>Zadejte WebDAV endpoint, například <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Zadejte uživatelské jméno a heslo.</li><li>Režim ověřování ponechte ve výchozím stavu <code>Basic</code>.</li><li>Úložný adresář ponechte <code>imgbed</code> nebo ho změňte na vlastní.</li><li>Klikněte na Uložit.</li><li>Po uložení zkontrolujte kartu kanálu, případně dotaz na kapacitu a nahrajte testovací soubor.</li></ol><h2 id="overeni" tabindex="-1">Ověření <a class="header-anchor" href="#overeni" aria-label="Permalink to &quot;Ověření&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Jak ověřit</th></tr></thead><tbody><tr><td>Karta kanálu se zobrazuje</td><td>Po uložení by se v Nastavení nahrávání měla zobrazit karta WebDAV.</td></tr><tr><td>Kanál je zapnutý</td><td>Přepínač v pravém horním rohu karty zůstává zapnutý.</td></tr><tr><td>Přihlašovací údaje jsou uloženy</td><td>Detail ukazuje Endpoint, uživatelské jméno, režim ověřování a úložný adresář.</td></tr><tr><td>Malý soubor se nahraje</td><td>Nahrajte testovací obrázek a ověřte, že se objeví ve WebDAV adresáři.</td></tr><tr><td>Pravidlo pro velké soubory funguje</td><td>Soubory nad 64 MiB používají chunk upload a vytvoří vzdálený chunk adresář.</td></tr><tr><td>Dotaz na kapacitu funguje</td><td>Pokud server podporuje informace o kapacitě, dotaz ukáže použité a celkové místo.</td></tr></tbody></table><p><img src="'+d+`" alt="Dotaz na kvótu byl úspěšný" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="proc-velke-webdav-soubory-vytvareji-chunk-adresar" tabindex="-1">Proč velké WebDAV soubory vytvářejí chunk adresář? <a class="header-anchor" href="#proc-velke-webdav-soubory-vytvareji-chunk-adresar" aria-label="Permalink to &quot;Proč velké WebDAV soubory vytvářejí chunk adresář?&quot;">​</a></h3><p>Je to aktuální způsob ukládání velkých souborů.</p><p>Soubory větší než 64 MiB se neslučují do jednoho velkého vzdáleného souboru. Ukládají se jako chunk adresář. ImgBed zaznamená manifest a vrací celý obsah čtením částí ve správném pořadí.</p><h3 id="co-zkontrolovat-jako-prvni-kdyz-selze-upload-velkych-souboru" tabindex="-1">Co zkontrolovat jako první, když selže upload velkých souborů? <a class="header-anchor" href="#co-zkontrolovat-jako-prvni-kdyz-selze-upload-velkych-souboru" aria-label="Permalink to &quot;Co zkontrolovat jako první, když selže upload velkých souborů?&quot;">​</a></h3><p>Nejdřív zkontrolujte Endpoint, uživatelské jméno, heslo a úložný adresář. Potom ověřte, že služba WebDAV dovoluje vytvářet adresáře, zapisovat soubory a číst soubory.</p><p>Pokud dotaz na kapacitu selže, ale malé soubory se nahrávají, server možná kapacitní informace nepodporuje nebo je omezuje. Neznamená to automaticky, že upload nefunguje.</p><h3 id="jaky-rezim-overovani-zvolit" tabindex="-1">Jaký režim ověřování zvolit? <a class="header-anchor" href="#jaky-rezim-overovani-zvolit" aria-label="Permalink to &quot;Jaký režim ověřování zvolit?&quot;">​</a></h3><p>Začněte s <code>Basic</code>.</p><p>Pokud server výslovně vyžaduje digest authentication, použijte <code>Digest</code>.</p><p>Pokud si nejste jistí, použijte automatické vyjednání.</p><h2 id="rychly-checklist" tabindex="-1">Rychlý checklist <a class="header-anchor" href="#rychly-checklist" aria-label="Permalink to &quot;Rychlý checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Připravte WebDAV endpoint, uživatelské jméno a heslo</span></span>
<span class="line"><span>-&gt; Otevřete Nastavení nahrávání</span></span>
<span class="line"><span>-&gt; Přidat kanál</span></span>
<span class="line"><span>-&gt; Vyberte WebDAV</span></span>
<span class="line"><span>-&gt; Zadejte Endpoint / uživatelské jméno / heslo</span></span>
<span class="line"><span>-&gt; Režim ověřování nechte výchozí Basic</span></span>
<span class="line"><span>-&gt; Úložný adresář nechte výchozí imgbed</span></span>
<span class="line"><span>-&gt; Uložte</span></span>
<span class="line"><span>-&gt; Dotaz na kapacitu</span></span>
<span class="line"><span>-&gt; Nahrajte testovací soubor</span></span></code></pre></div>`,45)])])}const j=n(s,[["render",p]]);export{y as __pageData,j as default};
